-- ============================================
-- Matryca tłumaczeń — import przez phpMyAdmin
-- Tworzy tabele (jeśli brak) + wgrywa 33 frazy i renditcje
-- ============================================
SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS=0;

CREATE TABLE IF NOT EXISTS `translation_phrases` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `slug` varchar(200) COLLATE utf8mb4_unicode_ci NOT NULL,
  `phrase_pl` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `product_count` int unsigned NOT NULL DEFAULT '0',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `translation_phrases_slug_unique` (`slug`)
) ENGINE=InnoDB AUTO_INCREMENT=556 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `translation_phrase_renditions` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `translation_phrase_id` bigint unsigned NOT NULL,
  `channel` varchar(60) COLLATE utf8mb4_unicode_ci NOT NULL,
  `value` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `source` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'sheet_import',
  `variants_count` int unsigned NOT NULL DEFAULT '1',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_phrase_channel` (`translation_phrase_id`,`channel`),
  KEY `translation_phrase_renditions_channel_index` (`channel`),
  CONSTRAINT `translation_phrase_renditions_translation_phrase_id_foreign` FOREIGN KEY (`translation_phrase_id`) REFERENCES `translation_phrases` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=5635 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `translation_overrides` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `translatable_type` varchar(60) COLLATE utf8mb4_unicode_ci NOT NULL,
  `translatable_id` bigint unsigned NOT NULL,
  `field` varchar(40) COLLATE utf8mb4_unicode_ci NOT NULL,
  `locale` varchar(60) COLLATE utf8mb4_unicode_ci NOT NULL,
  `source` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL,
  `user_id` bigint unsigned DEFAULT NULL,
  `locked_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_translation_override` (`translatable_type`,`translatable_id`,`field`,`locale`),
  KEY `translation_overrides_user_id_foreign` (`user_id`),
  KEY `idx_translation_override_owner` (`translatable_type`,`translatable_id`),
  CONSTRAINT `translation_overrides_user_id_foreign` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=26592 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

TRUNCATE translation_phrase_renditions;
TRUNCATE translation_phrases;



SET FOREIGN_KEY_CHECKS=1;
